I'll implement a robust RFC 4180 CSV parser using a state machine. This handles all the edge cases: quoted fields, escaped quotes, embedded newlines, CRLF/LF, BOM, and trailing newlines.

```typescript
export interface ParseCSVOptions {
  delimiter?: string;   // default: ","
  quote?: string;       // default: '"'
  newline?: string;     // default: auto-detect
}

type ParserState = 'FIELD_START' | 'IN_UNQUOTED' | 'IN_QUOTED' | 'AFTER_QUOTE';

/**
 * Parse RFC 4180-compliant CSV text into a 2D array of strings.
 *
 * Features:
 * - Handles quoted fields with embedded delimiters and newlines
 * - Escaped quotes (two consecutive quotes = one literal quote)
 * - CRLF and LF line endings
 * - UTF-8 BOM stripping
 * - Trailing newline suppression
 * - Configurable delimiter and quote characters
 *
 * @param input Raw CSV string
 * @param options Parser configuration
 * @returns 2D array of string fields
 */
export function parseCSV(input: string, options?: ParseCSVOptions): string[][] {
  // Configuration
  const delimiter = options?.delimiter ?? ',';
  const quoteChar = options?.quote ?? '"';

  // Strip UTF-8 BOM (\uFEFF) if present at start of input
  let text = input;
  if (text.charCodeAt(0) === 0xFEFF) {
    text = text.slice(1);
  }

  // Empty input produces empty array (not [['']])
  if (text.length === 0) {
    return [];
  }

  const result: string[][] = [];
  let currentRow: string[] = [];
  let currentField = '';
  let state: ParserState = 'FIELD_START';
  let pos = 0;
  const length = text.length;

  while (pos < length) {
    const char = text[pos]!;

    switch (state) {
      case 'FIELD_START':
        if (char === quoteChar) {
          // Beginning of a quoted field
          state = 'IN_QUOTED';
          pos++;
        } else if (char === delimiter) {
          // Empty unquoted field
          currentRow.push('');
          pos++;
        } else if (char === '\r') {
          // End of row (CR or CRLF)
          currentRow.push('');
          result.push(currentRow);
          currentRow = [];
          pos++;
          // Consume following LF if CRLF
          if (pos < length && text[pos] === '\n') {
            pos++;
          }
        } else if (char === '\n') {
          // End of row (LF only)
          currentRow.push('');
          result.push(currentRow);
          currentRow = [];
          pos++;
        } else {
          // Start of unquoted field
          currentField += char;
          state = 'IN_UNQUOTED';
          pos++;
        }
        break;

      case 'IN_UNQUOTED':
        if (char === delimiter) {
          currentRow.push(currentField);
          currentField = '';
          state = 'FIELD_START';
          pos++;
        } else if (char === '\r') {
          currentRow.push(currentField);
          currentField = '';
          result.push(currentRow);
          currentRow = [];
          state = 'FIELD_START';
          pos++;
          if (pos < length && text[pos] === '\n') pos++;
        } else if (char === '\n') {
          currentRow.push(currentField);
          currentField = '';
          result.push(currentRow);
          currentRow = [];
          state = 'FIELD_START';
          pos++;
        } else {
          currentField += char;
          pos++;
        }
        break;

      case 'IN_QUOTED':
        if (char === quoteChar) {
          // Could be end of field or escaped quote — check next char
          state = 'AFTER_QUOTE';
          pos++;
        } else {
          // All other characters (including newlines and delimiters) are literal
          currentField += char;
          pos++;
        }
        break;

      case 'AFTER_QUOTE':
        if (char === quoteChar) {
          // Escaped quote: "" inside quoted field = single literal quote
          currentField += quoteChar;
          state = 'IN_QUOTED';
          pos++;
        } else if (char === delimiter) {
          // End of quoted field, start of next
          currentRow.push(currentField);
          currentField = '';
          state = 'FIELD_START';
          pos++;
        } else if (char === '\r') {
          currentRow.push(currentField);
          currentField = '';
          result.push(currentRow);
          currentRow = [];
          state = 'FIELD_START';
          pos++;
          if (pos < length && text[pos] === '\n') pos++;
        } else if (char === '\n') {
          currentRow.push(currentField);
          currentField = '';
          result.push(currentRow);
          currentRow = [];
          state = 'FIELD_START';
          pos++;
        } else {
          // Non-standard: data after closing quote (lenient)
          currentField += char;
          state = 'IN_UNQUOTED';
          pos++;
        }
        break;
    }
  }

  // Flush the last field and row
  // Only add if there's something to add (prevents spurious empty row after trailing newline)
  if (state === 'IN_QUOTED' || state === 'AFTER_QUOTE' || currentField.length > 0 || currentRow.length > 0) {
    currentRow.push(currentField);
    result.push(currentRow);
  }

  return result;
}
```

This implementation correctly handles all the edge cases:
- RFC 4180 quoted fields with embedded delimiters and newlines
- Double-quote escaping ("" → ")
- CRLF and LF line endings (auto-detected)
- UTF-8 BOM stripping at start of input
- Trailing newline suppression
- Custom delimiter and quote characters via options
